var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"공군 기술 연구소 임시 선착장\\n델타 세븐 기함, 엔터프라이즈 <color=#ffd34c>개장 작업 중</color>\\nCSE Lv. <b>0</b>","JPN":"空軍技術研究所の臨時船着き場\\nデルタセブンの旗艦、エンタープライズの<color=#ffd34c>改装作業中</color>\\nCSE Lv. <b>0</b>","ENG":"Air Force Research Lab Temporary Dock,\\nDelta Seven Flagship, Enterprise <color=#ffd34c>undergoing remodeling</color>\\nCSE Lv. <b>0</b>","TWN":"空軍技術研究所臨時機庫\\n第七三角洲部隊艦船 企業號 <color=#ffd34c>改裝作業中</color>\\nCSE Lv. <b>0</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"매버릭, 그쪽 일은 어때?","JPN":"マーベリック、そっちはどう？","ENG":"How are things going Maverick?","TWN":"麥伯利，你那邊如何？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"말도 마. 엔진 갈아치우면 에이허브에 탑재된 기상 조절 시스템도 뜯어 놓으란다.","JPN":"最悪。エンジンを替えた後にはエイハブに搭載されてる天候調節システムも外しておけって。","ENG":"Don’t get me started. They said that once we’re done replacing the engine, we have to dismantle the weather control system attached to the Ahab.","TWN":"別說了，換掉引擎的話，原本搭載在亞哈上的氣象調節系統也要拆掉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그것도 열─두─ 시간 안에.","JPN":"それも十～二～時間内に。","ENG":"And they want this done in TWELVE. HOURS.","TWN":"而且還必須在12個小時內完成！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"역시 군인 놈들은 제정신이 아니야. 오늘 안에 방 정리 다 하라는 우리 엄마보다 더 심해.","JPN":"やっぱ軍人の奴らは正気じゃない。今日中に部屋の掃除を終わらせろっていうお母さんよりひどいんだ。","ENG":"I knew it, these military guys are nuts. They’re worse than my mom when she tells me to clean my room within today.","TWN":"軍人果然腦袋都不太正常，我媽頂多叫我今天之內把房間整理好，他們比我媽還超過！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"에잇! 이럴 줄 알았으면 차라리 편안한 수용소 안에 있는 건데!","JPN":"えいっ！　こうなるとわかってたら、いっそ楽な収容所に残っていればよかった！","ENG":"Damn it! If I knew it would be like this, I would’ve just stayed comfortably in prison!","TWN":"嘖！早知如此，還不如乾脆就待在收容所裡！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"거기선 몸이라도 편했다고! 밥도 맛있었고!","JPN":"あそこは少なくとも体は楽だったんだよ！　ご飯も美味しかったし！","ENG":"At least it was comfortable there! And the food was good!","TWN":"在所裡多舒適！連飯都比較好吃！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"군대 밥이 수용소 보다 더 맛없다니 이게 말이 돼?!","JPN":"軍隊のご飯が収容所よりまずいなんてあり得ないでしょう！？","ENG":"How can military food be more disgusting than prison food?!","TWN":"軍隊的伙食竟然比收容所的還差！這說得過去嗎？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"욕망에 굴복해선 안돼, 친구!","JPN":"欲望に負けるな、友よ！","ENG":"You must not give in to your urges, comrade!","TWN":"朋友，不能屈服於口腹之慾！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"우린 어둠 속에서 자유를 위해 투쟁하는 하나이자 일곱! 일곱이자 하나!","JPN":"私たちは闇の中で自由のために戦う一人で七人！　七人で一人！","ENG":"We fight for freedom within the darkness! Seven for one! One for seven!","TWN":"我們可是在黑暗中為自由而奮鬥的一群人，我們是七！是七也是一！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"다-크 세븐이라고.","JPN":"ダーークセブンなんだよ。","ENG":"We are Daark Seven.","TWN":"我們是Dark 7！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L14_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"분명 넘버 1이 우릴 구하러 올 거야!","JPN":"きっとナンバー1が私たちを助けに来てくれる！","ENG":"Surely Number 1 will come save us!","TWN":"1號一定會來救我們的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그, 그래, 넘버 1이라면 분명 우리가 이대로 고통 받게 내버려 둘 리 없어!","JPN":"そ、そう、ナンバー1ならきっと私たちが苦しんでるところを見捨てないはずだ！","ENG":"Th-that's right! Knowing Number 1, there’s no way that he’ll leave us suffering like this!","TWN":"嗯…你說的沒錯，1號不會讓我們就這樣一直受苦的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그리고…… 좀 미덥진 않지만 넘버2도 있고…….","JPN":"あと……ちょっと頼りないけどナンバー2もいるし……","ENG":"Also... Although not very trustworthy, there’s also Number 2...","TWN":"況且……還有不太靠譜2號……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"저, 정말? 넘버2가 우릴 도와줄까?","JPN":"ほ、本当？　ナンバー2が私たちを助けてくれるかな？","ENG":"R-really? But will Number 2 help us?","TWN":"真…真的嗎？2號會幫我們嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"솔직히 말하면…… 아니.","JPN":"正直に言うと……望み薄。","ENG":"To be honest... I don’t think so.","TWN":"說實話嗎……不會。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"……크흥! 사실 내 생각도 그래.","JPN":"……チーン！　実は私もそう思う。","ENG":"...Ahem! Honestly, I also don’t think so either.","TWN":"……咳咳！其實我也覺得不會。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"우리 의견이 같은 건 좋은 일이지만 내 셔츠로 코 풀지 마!","JPN":"同じ意見なのは嬉しいけど、私のシャツで鼻かまないでよ！","ENG":"It’s good that we see eye to eye, but don’t blow your nose on my shirt!","TWN":"我很高興我們有共識，但誰准你用我的襯衫擤鼻涕的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"거기 프리라이더 콤비, 손수건 좀 갖다 줄래?","JPN":"そこのフリーライダーコンビ、ハンカチ持ってきてくれる？","ENG":"You there, the Free Riders duo, can you bring me a handkerchief?","TWN":"我說免費騎士雙人組，手帕借一下吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"지금 함선 모듈 옮기는 거 안 보여요? 엄청 무겁다고요, 이거!","JPN":"今艦船のモジュール運んでる途中じゃないですか！　めっちゃ重いんですよ、これ！","ENG":"Can’t you see that we’re moving the ship module right now? It’s really heavy, you know!","TWN":"你沒看到我正在搬艦船模組嗎？這個很重欸！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L27_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"가, 가택 경비원에게 이런 중노동을 시키다니……. 너무해요……","JPN":"か、家宅の警備員にこんな重労働をさせるなんて……ひどいです……","ENG":"I-I can’t believe they’re making a homebody like me do such heavy labor... This is cruel...","TWN":"竟…竟然叫私人護衛做這種苦力……好過分……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"미안한데 어쩌겠어. 우리 중에 부족한 중장비를 대신해 줄 사람은 카운터인 너희뿐인걸.","JPN":"悪いけど仕方ないでしょ。私たちの中で足りない重装備の代わりに働いてくれそうな人はカウンターの二人だけなんだから。","ENG":"I’m sorry, but what else can we do? Out of the people here, the only ones who can act as alternatives for the heavy equipment that we don’t have are you Counters.","TWN":"不好意思，但我們也是有苦衷的。誰叫你們是制裁者，現在就只有制裁者能代替我們所缺乏的重型設備。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"일단 모듈이 다 조립돼야 시스템 쪽도 마무리 할 수 있으니까, 마지막까지 수고 좀 해 줘.","JPN":"とりあえすモジュールが組み立てられないとシステムも仕上げられないから、最後まで頑張って。","ENG":"Since we need to finish assembling the module to complete the system, we’ll need your help until this is done.","TWN":"因為要先組裝好模組才能完成系統面的作業，只好麻煩你們再辛苦一下囉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"안 그래, 넘버 5?","JPN":"なあ、ナンバー5？","ENG":"Isn’t that right, Number 5?","TWN":"5號，你說是不是？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"그렇다. 우리 중에는 육체 노동에 적합한 인원이 없으니까.","JPN":"そうだ。私たちの中では肉体労働に適合する者はいない。","ENG":"That’s right. None of us are fit for doing manual labor.","TWN":"是，我們當中沒有適合做苦力的人。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"그런데 왜 내가 넘버 5지? 다크 세븐의 새로운 멤버니까 넘버 8 아닌가?","JPN":"ところでなぜ私がナンバー5なのだ？　ダークセブンの新しいメンバーなのだから、ナンバー8ではないのか？","ENG":"By the way, why am I number 5? Shouldn’t I be Number 8 since I’m the newest member of the Dark Seven?","TWN":"不過為何我是5號？我不是 Dark 7的新成員嗎？那應該是8號吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"후후, 그런 고정관념이야 말로 사회가 우리에게 강요한 족쇄일 뿐이지.","JPN":"ふふ、そういう固定観念こそ社会が私たちに押し付けた足枷に過ぎないんだよ。","ENG":"Ha ha, that kind of stereotyping is merely a shackle forced upon us by society.","TWN":"呵呵，這只是社會硬加在我們身上的框架。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"명심해둬, 어둠의 정보전사 다-크 세븐의 이름은 인원수와는 관계없다고.","JPN":"よく覚えておけ、闇の情報戦士ダーークセブンの名は人数とは関係ない。","ENG":"Remember, for us Daark Seven, the Info Warriors of Darkness, our name has nothing to do with our number of members.","TWN":"你記住，黑暗的情報戰士Dark 7，這個名字和人數完全無關！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"맞아. 가장 어감이 좋고 멋져 보이는 숫자를 이름에 붙였을 뿐이지.","JPN":"そう。一番響きがよくてカッコよさそうな数字を名前に付けただけなんだよね。","ENG":"That’s right. We just added whatever number sounded the most appropriate and cool.","TWN":"沒錯，單純只是覺得這個數字好唸又帥而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"다-크 에잇이라니, 촌스러워서 참을 수 없다고.","JPN":"ダーークエイトなんて、ダサくてしょうがないんだよ。","ENG":"\\"Daark Eight\\", such a corny name.","TWN":" Dark 8，聽起來不是很俗嗎？我沒辦法接受。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그러니 빨리 가입할수록 더 좋은 번호를 선점할 수 있지, 너처럼.","JPN":"だから早く加入するほど、もっといい番号を先取りできる、お前のようにな。","ENG":"Therefore, the earlier you join us, the better the number you get assigned to yourself, just like in your case.","TWN":"所以數字是先搶先贏，就像你一樣。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"이제 빈자리도 둘 밖에 안 남았어. 행운으로 생각해.","JPN":"もう空席は二つだけだ。幸運だと思え。","ENG":"We only have two more empty seats now. Consider yourself lucky.","TWN":"現在餘額只剩兩個，算你幸運。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"과연…… 그런건가……!","JPN":"なるほど……そういうことなのか……！","ENG":"Oh…? Is that so...?!","TWN":"是……這樣嗎……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"가능성 데이터베이스에 경우의 수를 추가했다.","JPN":"可能性のデータベースに場合の数を追加した。","ENG":"I added a number of cases in the database of possibilities.","TWN":"已在可能性資料庫中添加情況變數。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그리고 다크 세븐이 아니야. 따라 해봐, 힘을 실어서! 다─크 세븐!","JPN":"あと､ダークセブンじゃない。私に続けて､力いっぱいに！　ダーークセブン!","ENG":"Also, it’s not just \\"Dark Seven\\". Repeat after me, with more force in your voice! DAARK SEVEN!","TWN":"而且唸的時候要注意，你跟我唸一遍，用力！Dark─7！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"다!─ 크! 세븐!","JPN":"ダーー！　ク！　セブン！","ENG":"DAARK! SEVEN!","TWN":"Dar！─k！7！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L48_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그렇지! 바로 그거야!","JPN":"そう！　それだよ！","ENG":"Way to go! That’s the spirit!","TWN":"很好！就是這樣！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"역시 우리가 눈여겨 본 멤버다워. 넘버 2랑 다르게 배우는 게 빠르다니까.","JPN":"やっぱ私たちが見込んだメンバーだね。ナンバー2とは違って飲み込みが早いんだから。","ENG":"You truly are a member that we saw potential in! Unlike Number 2, you’re a quick learner.","TWN":"不愧是我們看上的成員，學得很快，哪像2號。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"이렇게 간단한 걸 배우는게 느리다고?","JPN":"このように簡単なことの、飲み込みが遅いだと？","ENG":"It took so long for Number 2 to learn something this simple?","TWN":"如此簡單的事也學得很慢嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"그 넘버2라는 인간, 학습 능력이 떨어지는 편인가 보군.","JPN":"そのナンバー2という人間、学習能力が低いようだな。","ENG":"Number 2’s learning capability must be on the lower side.","TWN":"那個2號的學習能力應該很差吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"저 둘처럼.","JPN":"あの二人のように。","ENG":"Just like those two.","TWN":"就像那二位一樣。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"갑자기 우린 왜 끌어들이는 거예요?!","JPN":"なんでいきなり私たちを巻き込むんですか！？","ENG":"Why are you suddenly dragging us into this?!","TWN":"幹嘛突然扯到我們身上來啦？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"우린 그냥 델타 세븐 체험 캠프에 참가하면 지원금을 준다고 해서 온 거라고요!","JPN":"私たちはただ、デルタセブンの体験キャンプに参加すると支援金をもらえると聞いて来ただけなんです！","ENG":"We only came here because we were told that people who volunteer at the Delta Seven experience camp would receive support funding!","TWN":"我們是因為聽說參加第七三角洲部隊體驗營有錢拿才來的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"마, 맞아요. 테라사이드 전역에 참가했던 사람들에겐 우대사항이 있다고 해서 온 건데……","JPN":"そ、そうなんです。テラサイドの戦域に参加した人は優遇してくれるっていうから来たのに……","ENG":"Th-that’s right. We signed up because they said that priority will be given to people who participated in the Terraside battle...","TWN":"就…就是說啊，而且還說參加過特拉賽德戰役的人會有特別優待……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이, 이런 중노동을 시킬 줄은 몰랐어요.","JPN":"こ、こんな重労働をさせられるなんて知らなかったんです。","ENG":"W-we didn’t know we had to do heavy labor like this.","TWN":"沒…沒想到竟然叫我們做這種苦工。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그러고 보니 그쪽은 거기서 한 번도 본 적이 없는데 왜 은근슬쩍 여기 껴있는 거예요?","JPN":"そういえばそっちはそこで一度も見たことないのに、なにサラッとここにいるんですか？","ENG":"Come to think of it, I don’t think I’ve ever seen you out there once... So why are you even here?","TWN":"不過我好像沒看過你欸？你怎麼會混進來這裡？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"서, 설마 저 두 아저씨들처럼 무시무시한 중범죄자 출신인 건가요?","JPN":"ま、まさかあのおじさんたちのように恐ろしい重罪人なんですか？","ENG":"C-could it be that you’re a fearsome felon, just like those two guys?","TWN":"你…你該不會和那兩位大叔一樣，是可怕的重犯吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그렇게 보이진 않는데…… 역시 사람은 겉모습만으론 알 수 없나 봐요.","JPN":"そうは見えませんけど……やっぱり人って見た目だけでは判断できないものですね。","ENG":"You don’t look like a felon... But I guess you can’t judge a book by its cover.","TWN":"看起來不像啊……果然是人不可貌相呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"누가 중범죄자야!","JPN":"誰が重罪人だ！","ENG":"Who’re you calling a felon?!","TWN":"誰是重犯啦！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그래, 우린 현대사회의 희생양일 뿐이라고!","JPN":"そうだ、私たちは現代社会の生贄なんだよ！","ENG":"That’s right! We’re merely the sacrificial lambs of modern society!","TWN":"就是說！我們只是這個社會的代罪羔羊！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……테라사이드 전역이라면 나도 그 자리에 있었는데.","JPN":"……テラサイドの戦域なら私もその場にいたが。","ENG":"...Speaking of the Terraside battle, I was there too.","TWN":"……若是特拉賽德戰役，那我也有在場。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"물론 지루해서 잠들어 있긴 했지만.","JPN":"もちろん退屈で眠っていたがな。","ENG":"Although I fell asleep because I got bored.","TWN":"只是我當時無聊到睡著。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"흥! 그 난리통에 잠들어 있었다니 말이 안되잖아요?","JPN":"フン！　その修羅場で寝てたなんて、あり得ないでしょう？","ENG":"Hmph! How is it possible to fall asleep in all that ruckus?","TWN":"哼！打得你死我活的，怎麼可能睡得著！你唬我啊？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"솔직히 말해 봐요! 당신도 몰래 보상금을 노리고 온 거죠? 우리처럼!","JPN":"正直に言ってくださいよ！　あなたも報酬金目当てでこっそり来たんじゃないですか？　私たちのように！","ENG":"Be honest! You’re only after the reward money, right? Just like we are!","TWN":"你老實說！你是不是也想打賞金的主意？跟我們一樣！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_QM","text":{"KOREA":"시끄러워!","JPN":"やかましい！","ENG":"Shut up!","TWN":"吵死啦！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L25_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"……거 참 시끄러운 녀석들이군.","JPN":"……まったく、うるさい奴らだな。","ENG":"...Man, you girls are noisy.","TWN":"……你們好吵！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"나 때는 말이야, 중장비도 없이 하루에 컨테이너를 맨손으로 열 개씩 옮겼다고.","JPN":"昔はさ、重装備もなしに素手でコンテナを一日10個も運んだんだよ。","ENG":"Back in my day, we used to move ten containers a day with our bare hands. And with no heavy equipment at all!","TWN":"想當年，就算沒有重型設備，我一個人一天就可以扛十個貨櫃！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"너무 그러지 마, 어린 녀석들이 뭘 알겠어? 그저 우리가 만들어준 평화에 찌든 것뿐이잖아.","JPN":"やめろよ、子どもに何がわかるってんだ？　ただ俺たちが作ってやった平和に甘んじてるだけだろ。","ENG":"Don’t be too harsh on them. What do these youngsters know about hardship? They’re merely spoiled by the peace we made for them.","TWN":"說這些幹嘛？年輕人哪懂？他們只是享受我們努力而來的果實而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"하지만 가끔은 어른으로서 엄하게 지도해야 할 때도 있지.","JPN":"だが、たまには大人として厳しく指導しなきゃならねぇ時もある。","ENG":"However, as their elders, sometimes we have to be strict when guiding them.","TWN":"可是身為大人，有時候該教的還是要教吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그렇지 않으면 다시 혼란이 세상을 덮쳤을 때, 이겨나갈 힘을 기를 수 없을 테니까.","JPN":"そうじゃねえとこの世界が再び混乱に陥った時、耐えぬく力を養えねえからな。","ENG":"If we aren’t, they’ll never develop the strength to persevere when this world is plunged into chaos again.","TWN":"否則世界再次陷入混亂時，他們怎麼有能力能夠勝過呢！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"들었지, 아가씨? 그러니까 쉬지 말고 빨리빨리 움직이자고.","JPN":"聞いただろ？　お嬢ちゃん。だから休んでねえでさっさと働こうぜ。","ENG":"You heard that, young lady? Therefore, stop taking breaks and let’s get this done quick.","TWN":"小姐，聽到沒有？少在那邊摸魚，趕快動起來！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……이제 더는 못 참아!","JPN":"……もう我慢できない！","ENG":"…I can't take this anymore!","TWN":"……我真是忍無可忍！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아저씨들이나 노동의 즐거움에 푹 빠져 계세요!","JPN":"おじさんたちは労働をたっぷり楽しんでください！","ENG":"You old geezers can take all the joys of labor by yourselves!","TWN":"要搬大叔們你們自己去搬啦！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"지원금이고 뭐고 전 관둘 거예요!","JPN":"支援金も何も、私はやめます！","ENG":"I don’t care about the support funding or whatever other rewards! I quit!","TWN":"我不幹啦！支援金什麼的我也不要啦！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"애초에 돈을 벌기 위해 일을 하다니, 제 신조에도 어긋나는 일이에요!","JPN":"大体金を稼ぐために働くなんて、私のモットーにも合わないんです！","ENG":"Working for money went against my principles in the first place anyway!","TWN":"一開始是因為有錢賺我才來的，我才不想做這種事呢！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히, 히로세 씨? 어디 가요?","JPN":"ひ、廣瀬さん？　どこ行くんですか？","ENG":"M-Ms. Hirose? Where are you going?","TWN":"廣…廣瀨？你要去哪裡？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"뻔하잖아요! 이 지긋지긋한 곳에서 탈출할 거예요!","JPN":"決まってるでしょう！　このうんざりしたところから脱出します！","ENG":"Isn’t it obvious? I’m getting out of here!","TWN":"這不是很明顯嗎？我要離開這個鬼地方！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L43_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"어? 어어? 쟤들 어디 가?","JPN":"え？　ええ？　あいつらどこ行くんだ？","ENG":"Huh? W-what...? Where are they going?","TWN":"欸？欸欸欸？他們要去哪？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"이봐 돌아와! 목숨을 걸고 같이 싸운 전우를 버리다니 그럴 순 없어!","JPN":"おい、戻ってこい！　命をかけて一緒に戦った戦友を見捨てるなんて、あり得ねえだろうが！","ENG":"Hey, come back! You can’t just abandon your comrades like that!","TWN":"喂，回來啊！怎麼可以扔下一起出生入死的戰友呢！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그래! 하다못해 중장비가 도착할 때까지만이라도 일해달라고!","JPN":"そうだぞ！　せめて重装備が来るまでは働いてくれよ！","ENG":"That’s right! At least work until the heavy equipment arrives!","TWN":"對啊！起碼也等到重型設備來之後再走吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"……야, 근데 솔직히 방금 그 말은 좀 많이 쓰레기 같다.","JPN":"……おい、正直今の言葉はちょっとクズすぎたぞ。","ENG":"...Hey, to be honest though, that last comment you made was scummy.","TWN":"……喂，你說這種話還是人嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"맞아. 사람이 왜 그렇게 이기적이냐.","JPN":"そうだ。自己中すぎんだろ。","ENG":"Yeah. How can you be so selfish?","TWN":"對啊，做人怎麼可以這麼自私呢？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"하아……. 이럴 줄 알았으면 그냥 숙소에서 린 시엔 씨 시중이나 들고 있을 걸 그랬어요.","JPN":"はあ……こうなるとわかってたなら、いっそ宿でリン・シエンさんの世話でもしてればよかったです。","ENG":"Ugh... If I knew things would be like this, I would have just acted as Lin Xien’s servant at the lodging.","TWN":"哀……早知道我就待在宿舍伺候林·西恩還比較好！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하지만 무림과 관은 가까이 하면 안 된다면서 소집 통지서 보자마자 집으로 갔잖아요.","JPN":"でもヤクザと警察は互いに縄張りを荒らさないものだって言いながら、招集通知書見た途端家に帰ったじゃないですか。","ENG":"But didn’t she say that she can afford a blemish on her character, but not on her clothes? Then she went right back home after receiving that draft card.","TWN":"正所謂井水不犯河水，所以她一看到召集通知書就回家去啦。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……역시 세상에 우리 편은 아무도 없어요.","JPN":"……やっぱりこの世界に私たちの味方は誰もいないんです。","ENG":"There really is nobody on our side...","TWN":"……這個世界果然沒有人站在我們這一邊。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이젠 에이미도 없으니까 민서양도 맘을 굳게 먹어야 해요.","JPN":"もうエイミーもいないんですから、クロボシさんもしっかりしないとダメです。","ENG":"Now that even Amy is no longer with us, you must also steel yourself, Minseo.","TWN":"現在艾米又不在，你千萬不能動搖。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"네…… 그런데 우리 언제까지 걸어야 하는 거죠?","JPN":"はい……ところで私たち、いつまで歩くんですか？","ENG":"Okay... By the way, how much longer do we have to walk?","TWN":"好……不過我們要走到什麼時候？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그러고 보니 여기 올 때는 헬리콥터를 타고 왔던 것 같은데?","JPN":"そういえばここに来る時にはヘリだったような？","ENG":"Now that you mention it, didn’t we come here on helicopters...?","TWN":"這麼說來，我們來的時候是搭直升機來的吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"서, 설마 그 길을 전부 걸어가겠다는 건 아니죠?","JPN":"ま、まさかその道程を全部歩いて行こうってわけじゃないですよね？","ENG":"S-surely you don’t intend on walking all the way back?","TWN":"我…我們該不會都要用走的吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"제가 그렇게 성실할 리가 없잖아요! 부, 분명 여기 어딘가에 대중교통이 있을 거예요.","JPN":"私がそんなに真面目なわけないでしょう！　き、きっとこのあたりに公共交通機関があるはずです。","ENG":"There’s no way that I would be that hardcore! Th-there must be public transportation somewhere around here.","TWN":"我怎麼可能這麼呆！這…這附近一定有大眾交通工具的啦！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"……하지만 여긴 비밀 군사 기지인데. 그런 게 있을 리가……","JPN":"……でもここは秘密軍事基地ですよ。そんなものあるはずが……","ENG":"...But it’s a secret military base. I don’t think there will be any...","TWN":"……可是這裡是軍事秘密基地欸，會有大眾交通工具嗎……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저기! 저길 봐요! 버스가 오고 있어요!","JPN":"あそこ！　あれを見てください！　バスですよ！","ENG":"There! Look over there! A bus is coming this way!","TWN":"你看！那裡！有巴士來咧！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저, 정말이네요? 버스 와요! 히로세 씨 대단해요!","JPN":"ほ、本当ですね？　バスが来てます！　廣瀬さん、すごいです！","ENG":"Oh, there is! A bus is coming! You’re amazing, Ms. Hirose!","TWN":"真…真的欸！是巴士！你好厲害喔！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그런데…… 버스도 오고, 헬기도 오고, 그 뒤에 전차도 몰려 오는데요?","JPN":"でも……バスに、ヘリに、その後ろに戦車も押し寄せてきてるんですけど？","ENG":"Um... Not only is there a bus, but helicopters and even tanks are following it...","TWN":"可是……有巴士，也有直升機，還有戰車欸？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_AIR_SMALL_START"},{"id":"L18_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"정말 대중교통이 맞는 걸까요?","JPN":"本当に公共交通機関なのでしょうか？","ENG":"Are you sure that is for public transportation?","TWN":"確定是大眾交通嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어, 어라……?","JPN":"あ、あれ……？","ENG":"Err... Huh?","TWN":"呃……？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"이봐 너희들. 저쪽 기지 방향에서 오는 것 같은데, 델타 세븐 부대와 무슨 관계지?","JPN":"おい、君たち。あそこの基地から来てるようだが、デルタセブンとはなんの関係だ？","ENG":"You two. You seem to be coming from the base. What is your relationship with Delta Seven?","TWN":"喂，你們兩個！我看你們好像是從基地的方向過來的，你們和第七三角洲部隊是什麼關係？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히, 히로세 씨! 분위기가 심상치 않아요!","JPN":"ひ、廣瀬さん！　雰囲気がおかしいです！","ENG":"M-Ms. Hirose! Something doesn’t feel right!","TWN":"廣…廣瀨！好像不太對勁欸！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"거, 걱정 말아요! 이래봬도 예전에 에이미에게 히치하이킹 하는 법을 배웠다고요.","JPN":"し、心配しないでください！　こう見えても昔エイミーにヒッチハイクのやり方を教わったんです。","ENG":"D-don’t worry! I learned how to hitchhike from Amy before!","TWN":"別…別擔心！之前不是有和艾米學過怎麼搭便車嗎！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"적당히 분위기 맞춰서 칭찬 몇 마디만 해 주면 분명 공짜로 태워줄 거예요.","JPN":"適当に合わせてちょっと誉めてあげれば、きっとただで乗せてくるはずです。","ENG":"If we just go with the flow and drop a few compliments, they’ll definitely give us a free ride.","TWN":"先看一下氣氛，然後再稱讚幾句，對方應該就會讓我們搭便車吧！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어쩌면 불쌍해 보여서 밥도 사줄지 몰라요!","JPN":"もしかしたら可哀想だと思ってご飯をおごってくれるかもしれませんよ！","ENG":"They might even take pity on us and buy us a meal!","TWN":"說不定我們再裝一下可憐，對方還會請我們吃飯呢！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨랑 같이 다닌다는 사실이…… 제게도 가끔 민망할 때가 있어요.","JPN":"廣瀬さんと一緒だということが……たまに恥ずかしくなる時があります。","ENG":"Sometimes... I feel embarrassed being around with you, Ms. Hirose...","TWN":"和你一起行動……老實說我偶爾也有點不安。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저, 저희는 델타 세븐 부대와 아무 관련이 없어요!","JPN":"わ、私たちはデルタセブンとはなんの関係もありません！","ENG":"W-we aren’t connected to Delta Seven in any way!","TWN":"我…我們和第七三角洲部隊完全沒關係！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그냥 체험 캠프에 온 민간인 비슷한 거라고요.","JPN":"ただ体験キャンプに来た一般人のようなものです。","ENG":"We’re just civilians who participated in their experience camp.","TWN":"我們是來參加體驗營的普通人！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그러니까…… 저기 가까운 도시에 지하철 있는 곳 까지만 태워 주시면 안될까요?","JPN":"だから……近い街の地下鉄の駅まで乗せてもらえませんか？","ENG":"So... Can you just drop us off at the subway station in the nearest city?","TWN":"可以……載我們到鄰近城市有地鐵的地方嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"체험 캠프라고?","JPN":"体験キャンプだと？","ENG":"Experience camp?","TWN":"體驗營？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"여기는 선발대. 델타 세븐과…… 아무튼 관계 있어 보이는 인원들과 조우했다.","JPN":"こちら先発隊。デルタセブンと……とにかく関わりのありそうな者たちと遭遇した。","ENG":"This is Spearhead. We have encountered... individuals who seem to be connected with Delta Seven.","TWN":"這裡是先遣隊，發現應該和第七三角洲部隊……有關係的人士。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"……알겠다. 교신 종료.","JPN":"……了解。交信終了。","ENG":"...Roger that. Over and out.","TWN":"……是，收到，結束通訊。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"전원 전투 준비! 저항하면 사살해도 상관없다.","JPN":"全員戦闘準備！　抵抗する場合、射殺しても構わない。","ENG":"All hands prepare for battle! Kill them if they resist.","TWN":"全員準備戰鬥！反抗者死。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어, 어째서? 차를 태워달라고 했더니 다짜고짜 총을 겨누는 거죠?!","JPN":"ど、どうして？　車に乗せてって言ったのにいきなり銃を構えるんですか！？","ENG":"W-what should we do? I asked for a ride and they’re suddenly pointing guns at us!!","TWN":"為…為什麼？不過就是想搭個便車，幹嘛拿槍指著我們？！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아직도 모르시나요 히로세 씨? 우리에게 세상은 그냥 난이도 조절에 실패한 망겜이라고요.","JPN":"まだわからないんですか、廣瀬さん？　私たちにとってこの世界は、ただ難易度調整に失敗したクソゲーなんですよ。","ENG":"Don’t you get it Ms. Hirose? The world has come to get us, and it's game over!","TWN":"廣瀨，你還搞不清楚狀況嗎？世界對我們而言就像是難度調整失敗的糞Game。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이상한 비유 그만하고 얼른 뛰어요!","JPN":"変な例えはやめて、早く走りましょう！","ENG":"Enough with the weird idioms and just run!","TWN":"不要再說這些聽不懂的比喻，先逃命吧！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"응? 갑자기 웬 총성이야? 어디서 사격 연습이라도 하나?","JPN":"ああ？　いきなり銃声？　どこかで射撃の練習でもしてんのか？","ENG":"Hmm? Why do I hear gunshots? Are they doing firing practice nearby?","TWN":"嗯？怎麼突然有槍聲？是哪裡在進行射擊練習嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"저, 저기 좀 봐! 아까 떠났던 애들이야!","JPN":"あ、あれを見ろ！　さっき出てった子たちだ！","ENG":"L-look over there! It’s those kids who left earlier!","TWN":"欸，你看！是剛才離開的人！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아아아악! 사람 살려어어어어!","JPN":"きゃああああっ！　助けてええええ！","ENG":"Kyaaah! HEEEEEELP!","TWN":"啊啊啊！救命啊～～～！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"새카맣게 몰려와요! 새카맣게!!","JPN":"押し寄せてくるんです！　大勢！！","ENG":"They’re swarming like flies! Like flies!!","TWN":"追上來啦！好多人！！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"저건…… 군인들 같은데? 훈련 중인가?","JPN":"あれは……軍人だな？　訓練中なのか？","ENG":"Those are... soldiers? Is this a military drill?","TWN":"那些人……好像是軍人？是在訓練嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"아니. 가능성 트리 평가 분석에 따르면 진짜 공격일 확률 95% 이상이다.","JPN":"いいや。可能性ツリー評価の分析によると、本当の攻撃である確率は95％以上だ。","ENG":"No. Based on the possibility tree evaluation analysis, the probability of this being an actual attack is over 95%.","TWN":"不對，根據可能性樹的分析結果，有95%以上的機率是真的攻擊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"하하, 넘버 5가 아직 경험이 부족한가 본데 실전이라는 건 그리 쉽게 벌어지는 일이 아냐.","JPN":"はは、ナンバー5はまだ経験が足りないみたいだけど、実戦っていうのはそう簡単に始まらないんだよ。","ENG":"Haha, maybe it’s your lack of experience, Number 5, but actual combat doesn’t break out so easily.","TWN":"哈哈，年輕人終究是年輕人，哪有那麼容易就開戰的？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"기억해두라고, 단순한 가능성 확률 계산만으로는 현실을 정확히 분석할 수 없지.","JPN":"覚えておくといい、単なる可能性の確率計算だけでは現実は正確に分析できないってこと。","ENG":"Remember this: reality cannot be accurately analyzed purely with simple probability calculations.","TWN":"你記住，單憑計算可能性機率，是無法準備分析現實的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"과연, 덕분에 새로운 항목을 학습했다.","JPN":"なるほど、おかげで新しい項目を学習した。","ENG":"Oh... Thanks to you, I’ve acquired new knowledge.","TWN":"原來如此，謝謝你讓我有新的學習。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"정확히 우리가 있는 방향으로 미사일이 날아오고 있는데 공격이 아닐 수 있다니.","JPN":"正確に私たちのいる方向へミサイルが飛んできているというのに攻撃でない可能性があるなんてな。","ENG":"Despite a missile flying directly towards our exact location, this may not be an attack...","TWN":"導彈就這樣筆直地朝我們飛過來，結果竟然不是真的攻擊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"현실이란 정말 놀라운 가능성의 집합체인 듯 하다.","JPN":"現実というものは本当に驚くべき可能性の集合体のようだ。","ENG":"Reality truly is an amazing agglomeration of possibilities.","TWN":"所謂的現實，彷彿是驚人可能性的集合體。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"미사일이 날아온다니! 그런 건 빨리빨리 말해야지!","JPN":"ミサイルが飛んできてる！？　そういうことは早く言ってよ！","ENG":"There’s a missile flying in our direction?! You should’ve mentioned this earlier!!","TWN":"導彈飛過來？！這麼重要的事你怎麼不早說！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"호오, 빨리 말했다면 다른 가능성이 발생하는 건가?","JPN":"ほう、早く言えば違う可能性が発生するのか？","ENG":"Oh? If I told you this earlier, then would it have created another probability?","TWN":"喔？若是我早點說的話，會有不同的可能性嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"맞아! 저 멍청이 때문에 우리가 여기서 다 죽을 가능성이 조금 줄어들었겠지!","JPN":"そう！　あのバカのせいで私たちがここで皆殺しになる可能性がちょとは減っただろう！","ENG":"That’s right! It would’ve slightly decreased our chances of dying here because of his stupidity!","TWN":"沒錯！那我們全都死在這裡的可能性會減低一點！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"당장 엎드려!","JPN":"今すぐ伏せろ！","ENG":"Everybody, get down!","TWN":"快趴下！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"기지 경비 병력이 예상 외로 취약한 것 같군.","JPN":"基地の警備兵力が予想外に弱いようだな。","ENG":"The base’s defenses are surprisingly weak.","TWN":"基地的戒備兵力沒想到蠻弱的。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"계속 화력 지원하고 다음 명령을 지시 바란다.","JPN":"火力支援を続け、次の命令を指示してほしい。","ENG":"Requesting sustained fire support and our next orders.","TWN":"維持火力，等候下一個指示。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_NULL","text":{"KOREA":"수신 양호. <color=#ffd34c>진압</color> 작전을 시작한다.","JPN":"受信良好。<color=#ffd34c>鎮圧</color>作戦を開始する。","ENG":"Roger that. Commence <color=#ffd34c>suppression</color> operation.","TWN":"收訊良好。開始<color=#ffd34c>鎮壓</color>作戰。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};